// Support both direct JSON and webhook body wrapper
const raw = $input.first().json;
const body = raw.body || raw;
const resumeText = (body.resume_text || '').trim();

if (!resumeText) {
  throw new Error('resume_text is required in the request body');
}

// Trim to ~15 000 chars to stay within model token limits
const trimmed = resumeText.slice(0, 15000);

const schema = {
  contact:    { name: 'string', email: 'string', phone: 'string', linkedin: 'string', github: 'string' },
  summary:    'string',
  skills:     [{ category: 'string', items: ['string'] }],
  experience: [{ company: 'string', title: 'string', dates: 'string', bullets: ['string'] }],
  projects:   [{ name: 'string', tech: ['string'], bullets: ['string'] }],
  education:  [{ institution: 'string', degree: 'string', dates: 'string', gpa: 'string' }]
};

const prompt = `You are a precise resume data extraction assistant.

Extract all information from the resume below and return a single valid JSON object matching this schema exactly:
${JSON.stringify(schema, null, 2)}

Rules:
- Return ONLY valid JSON. No markdown fences, no comments.
- Do NOT invent information absent from the source text.
- Empty string "" for missing string fields; [] for missing arrays.
- Group skills into logical categories (Languages, Frameworks, Tools, Cloud, etc.).
- Preserve original bullet phrasing; clean whitespace and broken line-wraps.
- gpa should be a string like "3.8/4.0" or empty string.

RESUME:
---
${trimmed}
---

Return the JSON object now:`;

return [{ json: { prompt } }];

const response = $input.first().json;

// Handle Gemini API errors
if (response.error) {
  throw new Error('Gemini API error: ' + JSON.stringify(response.error));
}

let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Unexpected Gemini response structure: ' + JSON.stringify(response).slice(0, 300));
}

// Strip accidental markdown fences
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('JSON parse failed: ' + e.message + ' | Raw: ' + rawText.slice(0, 200));
}

const result = {
  contact:    parsed.contact    || { name: '', email: '', phone: '', linkedin: '', github: '' },
  summary:    parsed.summary    || '',
  skills:     Array.isArray(parsed.skills)     ? parsed.skills     : [],
  experience: Array.isArray(parsed.experience) ? parsed.experience : [],
  projects:   Array.isArray(parsed.projects)   ? parsed.projects   : [],
  education:  Array.isArray(parsed.education)  ? parsed.education  : []
};

return [{ json: result }];
